import React from 'react';
import PropTypes from 'prop-types';
import { makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';
import { CodeBlock, dracula } from "react-code-blocks";

function TabPanel(props) {
  const { value, index, code, language, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`code-tabpanel-${index}`}
      aria-labelledby={`code-tab-${index}`}
      {...other}
    >
      {value === index && (
          <CodeBlock
               text={code}
               language={language}
               showLineNumbers={false}
               theme={dracula}
              />
      )}
    </div>
  );
}

TabPanel.propTypes = {
  children: PropTypes.node,
  index: PropTypes.any.isRequired,
  value: PropTypes.any.isRequired,
};

function a11yProps(index) {
  return {
    id: `simple-tab-${index}`,
    'aria-controls': `simple-tabpanel-${index}`,
  };
}

const useStyles = makeStyles((theme) => ({
  root: {
    flexGrow: 1
    // backgroundColor: theme.palette.background.paper,
  },
  tab: {
    textTransform: 'none',
  }
}));

export default function CodeTab({ data }) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);

  const handleChange = (event, newValue) => {
    setValue(newValue);
  };

  return (
    <div className={classes.root}>
      <AppBar position="static">
        <Tabs
          value={value}
          onChange={handleChange}
          aria-label="code tabs"
        >
        {data.map((item, index) => (
          <Tab key={`tab-${index}`}  label={item.label} {...a11yProps(index)}  className={classes.tab} />
        ))}
        </Tabs>
      </AppBar>
      {data.map((item, index) => (
        <TabPanel
          key={`tabpanel-${index}`}
          value={value}
          index={index}
          code={item.code}
          language={item.language || 'bash' }
        />
      ))}
    </div>
  );
}

CodeTab.propTypes = {
  data: PropTypes.array.isRequired,
};
